import java.io.*;import java.util.*;
class Main{static int max(int[][]e){Arrays.sort(e,(a,b)->a[0]==b[0]?b[1]-a[1]:a[0]-b[0]);int[]tails=new int[e.length];int len=0;for(int[]p:e){int i=Arrays.binarySearch(tails,0,len,p[1]);if(i<0)i=-i-1;tails[i]=p[1];if(i==len)len++;}return len;}public static void main(String[]a)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);int[][]e=new int[n][2];for(int i=0;i<n;i++){e[i][0]=Integer.parseInt(d[idx++]);e[i][1]=Integer.parseInt(d[idx++]);}if(tc>0)out.append("\n\n");out.append(max(e));}System.out.print(out);}}
